// ❌ BAD — static global hides the dependency and breaks testability
public class Config { public static Config Instance { get; } = new(); }

// ✅ GOOD — Lazy<T> when DI is unavailable (correct thread-safe init)
private static readonly Lazy<Clock> _instance =
    new(() => new Clock(), LazyThreadSafetyMode.ExecutionAndPublication);
public static Clock Instance => _instance.Value;

// ✅ BEST — DI singleton: same guarantee, injectable and testable
services.AddSingleton<IClock, SystemClock>();

// ❌ BAD — separate factories allow mixing incompatible providers
