// ✅ GOOD (Abstract Factory) — create a MATCHED FAMILY from one provider
public interface IPaymentEcosystem {
    IPaymentGateway CreateGateway();
    IFraudDetector  CreateFraudDetector();
    IRefundHandler  CreateRefundHandler();
}
public class StripeEcosystem : IPaymentEcosystem {
    public IPaymentGateway CreateGateway()      => new StripeGateway();
    public IFraudDetector  CreateFraudDetector() => new StripeFraudDetector();
    public IRefundHandler  CreateRefundHandler() => new StripeRefundHandler();
}

