// ❌ BAD — shallow copy shares the Clauses list between original and clone
var master = new ContractTemplate("NDA", new() { "Confidentiality", "Term" }, 0m);
var clientCopy = master with { Title = "NDA - Acme Corp" };
clientCopy.Clauses.Add("Penalty"); // also mutates master — silent bug!

// ✅ GOOD — deep copy gives the clone its own independent Clauses list
var safeCopy = master with {
    Title   = "NDA - Acme Corp",
    Clauses = new List<string>(master.Clauses) // own copy, not shared
};

// ❌ BAD — Stripe SDK type leaks into the application layer
public class OrderService {
    private readonly StripeClient _stripe; // vendor type bleeds into domain
    public async Task Charge(decimal amount) =>
        await _stripe.Charges.CreateAsync(new ChargeCreateOptions { Amount = (long)(amount * 100) });
}

// ✅ GOOD — Adapter wraps Stripe; application layer sees only your interface
public interface IPaymentGateway {
    Task<PaymentResult> ChargeAsync(decimal amount, string token, CancellationToken ct);
}
public class StripeGatewayAdapter : IPaymentGateway {
    private readonly StripeClient _stripe;
    public StripeGatewayAdapter(StripeClient stripe) => _stripe = stripe;
    public async Task<PaymentResult> ChargeAsync(decimal amount, string token, CancellationToken ct) {
        var charge = await _stripe.Charges.CreateAsync(
            new ChargeCreateOptions { Amount = (long)(amount * 100), Source = token }, ct);
        return new PaymentResult(charge.Status == "succeeded", charge.Id);
    }
}

