// ✅ GOOD — Facade hides the subsystem; controller makes one call
public class CheckoutFacade {
    public async Task<OrderResult> PlaceOrderAsync(OrderRequest req, CancellationToken ct) {
        await _inventory.ReserveAsync(req.Items, ct);
        var pay  = await _payment.ChargeAsync(req.Total, req.Token, ct);
        var ship = await _shipping.ScheduleAsync(req.Address, ct);
        await _notify.ConfirmAsync(req.CustomerId, ct);
        return new OrderResult(pay.TransactionId, ship.TrackingId);
    }
}
