// ❌ BAD — one subclass per feature combination causes class explosion
class CachingProductRepo   : ProductRepository { }
class LoggingCachingRepo   : CachingProductRepo { } // new class per combo

// ✅ GOOD — Decorator: compose at runtime, same interface, no new subclasses
public class CachingProductRepo : IProductRepository {
    private readonly IProductRepository _inner;
    private readonly IMemoryCache _cache;
    public CachingProductRepo(IProductRepository inner, IMemoryCache cache) =>
        (_inner, _cache) = (inner, cache);
    public Task<Product> GetByIdAsync(int id, CancellationToken ct) =>
        _cache.GetOrCreateAsync($"product:{id}", _ => _inner.GetByIdAsync(id, ct))!;
}
// Wire with Scrutor — wraps transparently, no DI graph changes
services.AddScoped<IProductRepository, EfProductRepository>();
services.Decorate<IProductRepository, CachingProductRepo>();

// ❌ BAD — creating the expensive service eagerly even when rarely used
public class ReportController {
    private readonly RealReportService _svc = new RealReportService(); // always created
}

// ✅ GOOD — Proxy: lazy init + permission check, caller is unaware of both
public class ReportServiceProxy : IReportService {
    private readonly Lazy<RealReportService> _real = new(() => new RealReportService());
    private readonly IUserContext _user;
    public ReportServiceProxy(IUserContext user) => _user = user;
    public Report Generate(int id) {
        if (!_user.HasPermission("reports.read"))
            throw new UnauthorizedAccessException(); // protection proxy
        return _real.Value.Generate(id); // real object created here on first call
    }
}

