// ❌ BAD — action is not an object; undo is impossible, queueing is impossible
cart.AddItem(item); // no way to reverse, no way to defer

// ✅ GOOD — Command encapsulates the action so it can be stored and reversed
public interface ICommand { void Execute(); void Undo(); }
public class AddItemCommand : ICommand {
    private readonly ShoppingCart _cart;
    private readonly CartItem _item;
    public AddItemCommand(ShoppingCart cart, CartItem item) => (_cart, _item) = (cart, item);
    public void Execute() => _cart.Add(_item);
    public void Undo()    => _cart.Remove(_item); // knows how to reverse itself
}
var history = new Stack<ICommand>();
var cmd = new AddItemCommand(cart, item);
cmd.Execute(); history.Push(cmd);
history.Pop().Undo(); // remove the last added item

// ❌ BAD — subclass overrides Export() itself, breaking the locked sequence
public class BadCsvExporter : ReportExporter {
    public override void Export(ReportData d, string p) { /* does what it wants */ }
}

// ✅ GOOD — template method is sealed; subclass fills in variable steps only
public abstract class ReportExporter {
    public sealed void Export(ReportData data, string path) { // sequence is LOCKED
        var filtered  = Filter(data);     // varies per format
        var formatted = Format(filtered);  // varies per format
        Validate(formatted);              // hook: shared default, override if needed
        Write(formatted, path);           // varies per format
    }
    protected abstract ReportData Filter(ReportData d);
    protected abstract string     Format(ReportData d);
    protected virtual  void       Validate(string c) { } // hook with default
    protected abstract void       Write(string c, string path);
}
public class CsvExporter : ReportExporter {
    protected override ReportData Filter(ReportData d)  => d; // nulls removed
    protected override string     Format(ReportData d)  => "csv..."; // CSV lines
    protected override void       Write(string c, string p) => File.WriteAllText(p, c);
}

// ❌ BAD — one giant handler that does everything; no separation of concerns
app.Run(async ctx => {
    // authentication + rate-limiting + routing + logging all in one place
});

// ✅ GOOD — Chain of Responsibility: each link has one concern
app.Use(async (ctx, next) => {
    if (!ctx.User.Identity!.IsAuthenticated) {
        ctx.Response.StatusCode = 401;
        return; // SHORT-CIRCUIT: subsequent middleware never runs
    }
    await next(); // PASS: hand off to the next link in the chain
});
app.UseRateLimiting();
app.UseRouting();
app.MapControllers(); // terminal handler

